import React, { useState, useEffect } from 'react';
import { api } from '../api';
import { useAuth } from '../contexts/AuthContext';

export default function AdminPage() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const { user: currentUser } = useAuth();

  useEffect(() => {
    loadUsers();
  }, []);

  const loadUsers = async () => {
    try {
      setLoading(true);
      const response = await api.getUsers();
      setUsers(response.data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const toggleUserStatus = async (userId, isActive) => {
    if (!window.confirm(`${isActive ? 'Заблокировать' : 'Разблокировать'} пользователя?`)) return;
    try {
      await api.updateUser(userId, { isActive: !isActive });
      loadUsers(); // перезагружаем список
    } catch (err) {
      alert('Ошибка обновления');
    }
  };

  const changeRole = async (userId, newRole) => {
    try {
      await api.updateUser(userId, { role: newRole });
      loadUsers();
    } catch (err) {
      alert('Ошибка изменения роли');
    }
  };

  if (loading) return <div style={styles.loading}>Загрузка...</div>;

  return (
    <div style={styles.container}>
      <h2>👑 Админ-панель</h2>
      <p>Управление пользователями</p>

      <table style={styles.table}>
        <thead>
          <tr>
            <th>Email</th>
            <th>Имя</th>
            <th>Фамилия</th>
            <th>Роль</th>
            <th>Статус</th>
            <th>Действия</th>
          </tr>
        </thead>
        <tbody>
          {users.map(user => (
            <tr key={user.id} style={user.id === currentUser?.id ? styles.currentUser : {}}>
              <td>{user.email}</td>
              <td>{user.first_name}</td>
              <td>{user.last_name}</td>
              <td>
                <select
                  value={user.role}
                  onChange={(e) => changeRole(user.id, e.target.value)}
                  disabled={user.id === currentUser?.id}
                  style={styles.select}
                >
                  <option value="user">user</option>
                  <option value="seller">seller</option>
                  <option value="admin">admin</option>
                </select>
              </td>
              <td style={{ color: user.isActive ? '#4ade80' : '#ff4444' }}>
                {user.isActive ? 'Активен' : 'Заблокирован'}
              </td>
              <td>
                {user.id !== currentUser?.id && (
                  <button
                    onClick={() => toggleUserStatus(user.id, user.isActive)}
                    style={user.isActive ? styles.blockBtn : styles.unblockBtn}
                  >
                    {user.isActive ? 'Заблокировать' : 'Разблокировать'}
                  </button>
                )}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

const styles = {
  container: { padding: '20px', maxWidth: '1200px', margin: '0 auto' },
  table: { width: '100%', borderCollapse: 'collapse', marginTop: '20px' },
  th: { textAlign: 'left', padding: '10px', background: '#1a1f2e', color: '#4ade80' },
  td: { padding: '10px', borderBottom: '1px solid #333' },
  currentUser: { background: 'rgba(74, 222, 128, 0.1)' },
  select: { background: '#2a2f3e', color: 'white', border: '1px solid #333', padding: '5px', borderRadius: '4px' },
  blockBtn: { background: '#ff4444', color: 'white', border: 'none', padding: '5px 10px', borderRadius: '4px', cursor: 'pointer' },
  unblockBtn: { background: '#4ade80', color: '#0b0f19', border: 'none', padding: '5px 10px', borderRadius: '4px', cursor: 'pointer' },
  loading: { textAlign: 'center', padding: '40px', color: '#888' }
};
